const item = $input.first();
const data = item && item.json ? item.json : null;
const src = $('Валидация').first().json;
// PostgreSQL сбой: data может быть null или содержать .error поле — НЕ
// помечаем как unauthorized, иначе юзер видит ложный auth_required редирект.
if (data && data.error) {
  return [{ json: { token_valid: false, response: 'error', error: 'database_unavailable' } }];
}
if (!data || !data.user_id) {
  return [{ json: { token_valid: false, response: 'error', error: 'unauthorized', auth_required: true } }];
}
return [{ json: { ...src, token_valid: true, user_id: data.user_id } }];

// Форматируем список документов как человеко-читаемый ответ.
const rows = $input.all().map(i => i.json).filter(r => r && r.filename);
let response;
if (!rows.length) {
  response = 'В базе документов пока ничего нет. Загрузите файлы через «Загрузка документов» на дашборде.';
} else {
  const NL = String.fromCharCode(10);
  const lines = rows.map((r, idx) => {
    const n = r.chunks ? ' (' + r.chunks + ' фрагм.)' : '';
    return (idx + 1) + '. ' + r.filename + n;
  });
  response = 'Загружено документов: ' + rows.length + '.' + NL + lines.join(NL);
}
return [{ json: { response } }];

// R8.35: объединяем результаты от двух Поисков (через Merge append).
// Каждый item имеет поле source ('наш'|'внешний'). Чистим ошибки/пустоты,
// сортируем по similarity DESC, оставляем top 5.
const all = $input.all().map(i => i.json);
const clean = all.filter(r => r && !r.error && r.chunk_text && r.chunk_text.trim && r.chunk_text.trim().length > 0);
clean.sort((a, b) => (b.similarity || 0) - (a.similarity || 0));
const top = clean.slice(0, 5);
return top.map(r => ({ json: r }));
